SELECT t.*, creator.id as creator_id, creator.name as creator_name, creator.username as creator_username, `groups`.id as assignee_id, `groups`.name as assignee_name FROM tickets t LEFT JOIN users creator ON t.created_by = creator.id LEFT JOIN `groups` `groups` ON t.assigned_to = `groups`.id WHERE t.status IN
#{status}
AND t.assigned_to = #{groupId}

SELECT COUNT(*)
FROM tickets
WHERE assigned_to = #{userId} AND status = #{status}

SELECT COUNT(*)
FROM tickets
WHERE 1=1

    AND type = #{type}


    AND status = #{status}


    AND priority = #{priority}


    AND assigned_to = #{assignedTo}


    AND created_at >= #{createdAfter}

SELECT status, COUNT(*) as count FROM tickets
AND type = #{type}
GROUP BY status
